sql.foreach:
SELECT unpivot_t.table_name, unpivot_t.source_id, unpivot_t.column_name,
                unpivot_t.column_val
      FROM (SELECT '${table.tableName}' table_name, 

    ${table.selectArea}, 


    convert(VARCHAR(MAX), 


            ${column.tableAbbreviation}.${column.columnName}


            ${column.columnName}



        , ${column.convertStyle}

    ) 


            AS ${column.alias}


            AS ${column.columnName}



 FROM 


        ${table.tableArea}


        ${table.tableName} ${table.tableAbbreviation}



        WHERE 1 = 1


     AND ${table.whereArea} 




            ${column.tableAbbreviation}.${column.columnName}


            ${column.columnName}



  LIKE #{criteria.queryValue, jdbcType = VARCHAR} ) a
            unpivot(column_val FOR column_name IN 



            ${column.alias}


            ${column.columnName}



 ) unpivot_t

